<template>
  <v-container>
    <v-row class="d-flex justify-center mb-9">
      <v-col cols="12" sm="12" md="12" lg="12">
        <v-card class="mx-auto card-table" width="100%">
          <v-data-table-server
            :headers="headers"
            :items="products"
            :loading="loading"
            hide-default-footer
            fixed-header
            height="680"
            loading-text="جاري التحميل يرجى الأنتظار"
            :mobile-breakpoint="0"
          >
            <template v-slot:top>
              <v-toolbar flat color="#ffffff" class="mt-2">
                <h3 class="mx-2">نقطة البيع</h3>
                <v-divider class="mx-2" inset vertical></v-divider>
                <v-tooltip location="bottom" interactive>
                  <template v-slot:activator="{ props }">
                    <v-btn @click="reset_table" fab icon x-small v-bind="props">
                      <Icon
                        icon="solar:smartphone-update-bold"
                        color="#624fc6"
                        width="30"
                      />
                    </v-btn>
                  </template>
                  <span>تحديث معلومات الجدول</span>
                </v-tooltip>

                <v-tooltip location="bottom" interactive>
                  <template v-slot:activator="{ props }">
                    <v-btn
                      @click="add_sales"
                      fab
                      icon
                      x-small
                      v-bind="props"
                      :loading="loading_sale"
                    >
                      <Icon
                        icon="fluent:book-add-28-filled"
                        color="#624fc6"
                        width="32"
                      />

                      <template v-slot:loader>
                        <span class="custom-loader">
                          <v-icon color="#624fc6">mdi-cached</v-icon>
                        </span>
                      </template>
                    </v-btn>
                  </template>
                  <span>اضافة فاتورة</span>
                </v-tooltip>

                <v-spacer></v-spacer>
                <v-text-field
                  v-model="barcode_query"
                  @input="query_change"
                  append-inner-icon="mdi-magnify"
                  label="بحث"
                  :class="display.smOnly ? 'mb-2' : ''"
                  class="font-weight-black mx-2"
                  color="#624fc6"
                  variant="outlined"
                  rounded
                  clearable
                  hide-details
                />
              </v-toolbar>
            </template>

            <template v-slot:item="{ item, index }">
              <tr>
                <td class="text-center font-weight-black">
                  {{ item.barcode }}
                </td>

                <td class="text-center font-weight-black">
                  {{ item.product.name }}
                </td>

                <td class="text-center font-weight-black">
                  <h4 v-if="item.product.type == 0">ملابس</h4>
                  <h4 v-else-if="item.product.type == 1">حذاء</h4>
                </td>

                <td class="text-center font-weight-black">
                  <v-swatches
                    v-model="item.color"
                    :disabled="true"
                  ></v-swatches>
                </td>

                <td class="text-center font-weight-black">
                  <div
                    v-for="(subItem, subIndex) in item.items"
                    :key="subIndex"
                  >
                    <v-btn
                      :variant="
                        selectedItemPerRow[`${index}`]?.id === subItem.id
                          ? 'flat'
                          : 'outlined'
                      "
                      :disabled="
                        subItem.status == 'sold_out' ||
                        subItem.quantity == 0 ||
                        isSizeSelectedElsewhere(subItem.id, index)
                      "
                      class="mx-auto my-1"
                      style="border-radius: 16px"
                      :color="
                        subItem.status === 'available' ? '#624fc6' : '#C62828'
                      "
                      @click="selectSize(index, item, subItem)"
                    >
                      <h4>{{ subItem.size }}</h4>
                    </v-btn>
                  </div>
                </td>

                <td class="text-center font-weight-black">
                  <span
                    v-if="selectedItemPerRow[`${index}`]"
                    style="display: flex; align-items: center"
                  >
                    <v-btn
                      size="large"
                      style="border-radius: 15px !important"
                      color="#424242"
                      density="compact"
                      icon="mdi-plus"
                      @click="changeQuantity(index, item, 'inc')"
                    />
                    <h3 class="mx-4">
                      {{ selectedItemPerRow[`${index}`].quantity }}
                    </h3>
                    <v-btn
                      size="large"
                      style="border-radius: 15px !important"
                      color="#424242"
                      density="compact"
                      icon="mdi-minus"
                      @click="changeQuantity(index, item, 'dec')"
                    />
                  </span>
                  <span v-else>اختر القياس أولاً</span>
                </td>

                <td class="text-center font-weight-black">
                  <h3 v-if="selectedItemPerRow[`${index}`]">
                    {{ getSelectedItemQuantity(index, item) }}
                  </h3>
                  <span v-else>اختر القياس</span>
                </td>

                <!-- ★ هنا قمنا باستبدال خلية السعر بعنصر Selects لعمل خصم لكل سطر -->
                <td class="text-center font-weight-black">
                  <div v-if="selectedItemPerRow[`${index}`]" class="mt-2"> 
                    <Selects
                      :items="discountOptionsFor(item.selling_price)"
                      itemValue="value"
                      itemText="type"
                      :clearable="false"
                      :model-value="
                        selectedItemPerRow[`${index}`]?.discount ?? 0
                      "
                      v-on:update-value="
                        (val) =>
                          setDiscountOption(index, val, item.selling_price)
                      "
                      class="mx-auto"
                    />
              
                  </div>
                  <div v-else>{{ formatNumber(item.selling_price) }} د.ع</div>
                </td>

                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        @click="pop_delete_product(index)"
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#C62828"
                      >
                        <Icon
                          icon="ic:round-delete-forever"
                          color="#C62828"
                          width="32"
                        />
                        <template v-slot:loader>
                          <span class="custom-loader">
                            <v-icon color="#624fc6">mdi-cached</v-icon>
                          </span>
                        </template>
                      </v-btn>
                    </template>
                    <span>حذف</span>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>

          <v-card-text class="py-1">
            <v-col col="12" sm="3" md="3" lg="3" class="px-0 mx-0">
              <Selects
                v-on:update-value="sale_type = $event"
                v-model="sale_type"
                label="نوع الشراء"
                itemValue="value"
                itemText="type"
                :items="sale_types"
                class="px-0 mx-0"
              />
            </v-col>
          </v-card-text>
          <v-card-actions class="mb-5 mr-3">
            <h3>
              المجموع الكلي : {{ formatNumber(totalPrice) }} د.ع
            </h3></v-card-actions
          >
        </v-card>
      </v-col>
      <PopSalesDebitOrDelivery
        :dialog="dialog"
        @popClose="dialog = false"
        @addSales="addSales"
      />
    </v-row>
  </v-container>
</template>

<script setup>
import { ref, computed } from "vue";

import { useGoodsStore } from "@/stores/goods";
import { useSalesStore } from "@/stores/sales";
import { useDisplay } from "vuetify";
import { h, render } from "vue";
import { nextTick } from "vue";
import InvoiceReceipt from "@/components/layout/invoice.vue";
import PopSalesDebitOrDelivery from "@/components/sales/PopSalesDebitOrDelivery.vue";
import Selects from "@/components/layout/Selects.vue";

const display = useDisplay();

// Use Pinia stores
const goodsStore = useGoodsStore();
const salesStore = useSalesStore();

const selectedItemPerRow = ref({});
const paperSize = ref("size-80");
const nameStore = ref("علاء حداد فرع الديوانية");
const sale_type = ref({ type: "نقد", value: 0 });
const sale_types = [
  { type: "نقد", value: 0 },
  { type: "آجل", value: 1 },
  { type: "توصيل", value: 2 },
];

const dialog = ref(false);

const headers = [
  {
    title: "باركود",
    value: "barcode",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "المنتج",
    value: "name",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "نوع",
    value: "name",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "اللون",
    value: "color",
    align: "center",
    width: "130px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "القياس",
    value: "size",
    align: "center",
    width: "170px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "الكمية",
    value: "quantity",
    align: "center",
    width: "170px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "الكمية المتوفرة",
    value: "quantity",
    align: "center",
    width: "170px",
    headerProps: { class: "white--text text-body-1" },
  },

  {
    title: "السعر",
    value: "selling_price",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "العمليات",
    value: "operations",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
];

// Computed bindings to Pinia
const barcode_query = computed({
  get: () => goodsStore.barcode_query,
  set: (val) => (goodsStore.barcode_query = val),
});

const products = computed(() => goodsStore.temp_products);
const loading = computed(() => goodsStore.table_temp_product_loading);
const loading_sale = computed(() => salesStore.loading);

// Helper: simple number formatter (يمكنك استبداله بـ $filters إذا أردت)
const formatNumber = (n) => {
  if (n == null || n === undefined) return 0;
  return new Intl.NumberFormat().format(Number(n));
};

const toNumber = (v) => {
  if (v === null || v === undefined) return 0;
  if (typeof v === "number" && Number.isFinite(v)) return v;
  // تزيل فواصل الآلاف والمسافات العربية إن وجدت ثم تحول
  const s = String(v).replace(/[,،\s]/g, "");
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
};

// قائمة قيم الخصم (بالدينار). تشمل 0 = بدون خصم، و 5/10/15
const discountValues = [0, 5000, 10000, 15000];

// تبني خيارات الـ Selects لكل سعر مرّ على أساس سعر المنتج
function discountOptionsFor(price) {
  const p = Number(price);
  return discountValues.map((d) => {
    const finalP = Math.max(0, p - d);
    return {
      type:
        d === 0
          ? `${formatNumber(p)} د.ع (بدون خصم)`
          : `${formatNumber(finalP)} د.ع - خصم ${d} د.ع`,
      value: d, // نخزن قيمة الخصم كرقم، نعالج final_price من جهة الـ set
    };
  });
}

// اختيار القياس: نعطي العنصر المختار خصائص اضافية (discount, final_price...)
function selectSize(index, item, subItem) {
  // تأكد من وجود المنتجات
  selectedItemPerRow.value[index] = {
    id: subItem.id,
    name: item.product.name,
    size: subItem.size,
    price: toNumber(item.selling_price),
    dozen_id: subItem.dozen_id,
    quantity: 1,
    discount: 0,
    final_price: toNumber(item.selling_price),
  };
}

// عند تغيير اختيار الخصم من الـ Selects
function setDiscountOption(index, discountValue, basePrice) {
  if (!selectedItemPerRow.value[index]) return;

  // إذا جاء الكائن كاملاً، نحاول استخراج .value أو .value.value
  let discountNum = 0;
  if (discountValue !== null && typeof discountValue === "object") {
    // عدة احتمالات حسب طريقة إرسال الـ Selects
    discountNum = toNumber(discountValue.value ?? discountValue);
  } else {
    discountNum = toNumber(discountValue);
  }

  // تأكد من قاعدة السعر (قد يمر كـ string مع فواصل)
  const base = toNumber(basePrice ?? selectedItemPerRow.value[index].price ?? 0);

  const finalP = Math.max(0, base - discountNum);

  selectedItemPerRow.value[index].discount = discountNum;
  selectedItemPerRow.value[index].final_price = finalP;
}

// حساب المجموع الكلي بناءً على final_price لكل عنصر
const totalPrice = computed(() => {
  let total = 0;
  Object.entries(selectedItemPerRow.value).forEach(([key, selected]) => {
    const index = parseInt(key);
    const product = products.value[index];

    if (product && selected) {
      // تحويل آمن للقيمة النهائية والكمية
      const unit = toNumber(selected.final_price ?? product.selling_price ?? selected.price ?? 0);
      const qty = toNumber(selected.quantity ?? 0);
      total += qty * unit;
    }
  });

  return total;
});

// بقية الدوال لم تتغير كثيرا (مع تحديث طفيف لتمرير الخصم عند الإرسال)
function get_products_by_barcode() {
  if (
    barcode_query.value != null &&
    barcode_query.value != undefined &&
    barcode_query.value != "" &&
    barcode_query.value.length > 0
  ) {
    goodsStore.get_products_by_barcode();
    barcode_query.value = null;
  }
}

function changeQuantity(index, row, type) {
  const selected = selectedItemPerRow.value[index];
  if (!selected) return;

  const selectedItem = row.items.find((i) => i.id === selected.id);
  if (!selectedItem) return;

  if (type === "inc") {
    if (selected.quantity < selectedItem.quantity) {
      selected.quantity++;
    }
  } else if (type === "dec" && selected.quantity > 1) {
    selected.quantity--;
  }
}

function getSelectedItemQuantity(index, row) {
  const selected = selectedItemPerRow.value[index];
  if (!selected) return 0;

  const selectedItem = row.items.find((i) => i.id === selected.id);
  return selectedItem ? selectedItem.quantity : 0;
}

function isSizeSelectedElsewhere(subItemId, currentRowIndex) {
  return Object.entries(selectedItemPerRow.value).some(([key, val]) => {
    return key !== currentRowIndex.toString() && val.id === subItemId;
  });
}

function pop_delete_product(index) {
  if (index >= 0 && index < products.value.length) {
    products.value.splice(index, 1);

    if (selectedItemPerRow.value[index]) {
      delete selectedItemPerRow.value[index];
    }

    // إعادة بناء المفاتيح كي تبقى متوافقة مع الـ index
    const newSelected = {};
    Object.entries(selectedItemPerRow.value).forEach(([key, val]) => {
      const keyNum = parseInt(key);
      if (keyNum < index) newSelected[key] = val;
      else if (keyNum > index) newSelected[keyNum - 1] = val;
    });
    selectedItemPerRow.value = newSelected;
  }
}

let timerId = null;

function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_products_by_barcode();
  }, 200);
}

function reset_table() {
  goodsStore.temp_products = [];
  goodsStore.barcode_query = null;
  selectedItemPerRow.value = {};
}

let isPrinting = false;

function printInvoice(items) {
  if (isPrinting) return;
  isPrinting = true;

  // حاوية الطباعة المباشرة تحت body
  const container = document.createElement("div");
  container.id = "print-root"; // مهم جداً للـ CSS أدناه
  container.style.position = "fixed";
  container.style.left = "0";
  container.style.top = "0";
  container.style.zIndex = "2147483647";
  document.body.appendChild(container);

  const cleanup = () => {
    render(null, container);
    container.remove();
    window.removeEventListener("afterprint", cleanup);
    isPrinting = false;
  };

  const vnode = h(InvoiceReceipt, {
    purchasedItems: items.sale_items,
    nameStore: nameStore.value,
    paperSize: paperSize.value,
    saleType: sale_type.value.value,
    invoiceId: items.invoice_number,
    date: items.created_at,
    onReady: async () => {
      await nextTick();
      requestAnimationFrame(() => {
        window.addEventListener("afterprint", cleanup, { once: true });
        window.print(); // نسخة واحدة فقط
      });
    },
  });

  render(vnode, container);
}

async function add_sales() {
  if (sale_type.value.value != 0) {
    dialog.value = true;
  } else {
    addSales(null);
  }
}

async function addSales(info_user) {
  if (Object.keys(selectedItemPerRow.value).length > 0) {
    let data = {};
    // نحول الشكل الداخلي إلى مصفوفة مفهومة للـ backend
    const variantsArray = Object.entries(selectedItemPerRow.value).map(
      // eslint-disable-next-line no-unused-vars
      ([key, sel]) => ({
        id: sel.id,
        dozen_id: sel.dozen_id,
        product_name: sel.name,
        size: sel.size,
        price: Number(sel.price),
        quantity: Number(sel.quantity),
        discount_amount: Number(sel.discount ?? 0), // المبلغ المخصوم لكل وحدة
        final_price: Number(sel.final_price ?? sel.price),
      })
    );

    data["variants"] = variantsArray;
    data["sale_type"] = sale_type.value.value;
    if (info_user != null && info_user != undefined) {
      data["name"] = info_user["name"];
      data["city"] = info_user["city"];
      data["phone"] = info_user["phone"];
    }

    try {
      const response = await salesStore.add_sales(data);
      const sales = response.data.result[0];
      printInvoice(sales);
      reset_table();
    } catch (error) {
      console.error("حدث خطأ أثناء إضافة المبيعات:", error);
    }
  }
}
</script>

<style scoped>
.card-table {
  box-shadow: 0px 0px 0px 0px !important;
  border-radius: 25px !important;
}
</style>
